// 模拟后端搜索接口
const mockSearchFromServer = async (keyword: string): Promise<TreeNodeConfig[]> => {
  // 模拟API延迟
  await new Promise(resolve => setTimeout(resolve, 300));
  return searchTreeNodes(mockData, keyword);
};

const findNodeByKey = (nodes: TreeNodeConfig[], key: string): TreeNodeConfig | null => {
  for (const node of nodes) {
    if (node.value === key) {
      return node;
    }
    if (node.children) {
      const found = findNodeByKey(node.children, key);
      if (found) {
        return found;
      }
    }
  }
  return null;
};

const mockLoadData = async (key: string): Promise<TreeNodeConfig[]> => {
  // 模拟API延迟
  await new Promise(resolve => setTimeout(resolve, 300));

  // 查找对应的节点
  const targetNode = findNodeByKey(mockData, key);

  // 如果找到节点并且有子节点，返回子节点
  if (targetNode?.children) {
    return targetNode.children;
  }

  // 如果没有找到节点或节点没有子节点，返回空数组
  return [];
};

// 合并搜索结果到现有树结构
const mergeSearchResultToTree = (originalTree: TreeConfig, searchResults: TreeNodeConfig[]): TreeConfig => {
  const newTree = [...originalTree];

  searchResults.forEach(result => {
    const existingNodeIndex = newTree.findIndex(node => node.value === result.value);

    if (existingNodeIndex === -1) {
      // 如果节点不存在，直接添加
      newTree.push(result);
    } else {
      // 如果节点存在且有子节点，递归合并子节点
      const existingNode = newTree[existingNodeIndex];
      if (result.children && result.children.length > 0) {
        newTree[existingNodeIndex] = {
          ...existingNode,
          children: existingNode.children
            ? mergeSearchResultToTree(existingNode.children, result.children)
            : result.children,
        };
      }
    }
  });

  return newTree;
};

