export const Dynamic = () => {
  // It's just a simple demo. You can use tree map to optimize update perf.

  const [treeData, setTreeData] = useState(loadableTreeDate);
  const [checkable, setCheckable] = useState(false);
  const [loading, setLoading] = useState(false);

  return (
    <Space>
      <p>
        <Switch checked={checkable} onChange={e => setCheckable(e)} title="ddd" />
        <span>Checkable </span>
      </p>
      <Cascader
        mode="multiple"
        checkable={checkable}
        options={treeData}
        loadData={({ key, children }) => {
          console.log(key, children);
          return new Promise<void>(resolve => {
            if (children) {
              resolve();
              return;
            }
            setTimeout(() => {
              setTreeData(origin =>
                updateTreeData(origin, key, [
                  { label: `${key}-0`, value: `${key}-0` },
                  { label: `${key}-1`, value: `${key}-1` },
                ]),
              );

              resolve();
            }, 1000);
          });
        }}
        onSelect={console.log}
        style={{ width: 300 }}
      />
      <Cascader
        mode="multiple"
        checkable
        style={{ width: 300 }}
        options={treeData}
        loading={loading}
        loadData={({ key }) =>
          new Promise<void>(resolve => {
            mockLoadData(key).then(children => {
              setTreeData(origin => updateTreeData(origin, key, children));
              resolve();
            });
          })
        }
        expandTrigger="hover"
        showSearch
        onSearch={async (inputValue, { action }) => {
          if (action === 1 && inputValue) {
            setLoading(true);
            try {
              const searchResults = await mockSearchFromServer(inputValue);
              const mergedTreeData = mergeSearchResultToTree(treeData, searchResults);
              setTreeData(mergedTreeData);
            } catch (error) {
              console.error('搜索失败:', error);
            } finally {
              setLoading(false);
            }
          }
        }}
        defaultOpen={__SCREENSHOT__}
      />
    </Space>
  );
};

export const InnerCascade = () => {
  const [treeData, setTreeData] = useState(loadableTreeDate);
  const cascadeRef = React.useRef<CascadeRef>(null);
  return (
    <Space direction="vertical">
      <Button onClick={() => cascadeRef.current?.scrollIntoView('33', { offset: 100 })}>Scrollto </Button>
      <Cascade options={options} ref={cascadeRef} multiple />
      <Cascade options={options} expandTrigger="hover" />
      <Cascade
        options={treeData}
        loadData={({ key, children }) => {
          console.log(key, children);
          return new Promise<void>(resolve => {
            if (children) {
              resolve();
              return;
            }
            setTimeout(() => {
              setTreeData(origin =>
                updateTreeData(origin, key, [
                  { label: `${key}-0`, value: `${key}-0`, isLeaf: true },
                  { label: `${key}-1`, value: `${key}-1`, isLeaf: true },
                ]),
              );
              resolve();
            }, 1000);
          });
        }}
      />
    </Space>
  );
};

